INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (754, 174640, 6, 1205, '巫婆的眼泪', '&nbsp;&nbsp;报上看过一则《巫婆与王子》的故事：巫婆爱上了王子，可王子却深恋着公主。有一天，公主得了重病，王子求巫婆救回他爱人脆弱的生命。那是重症，巫婆不愿看到王子伤心，于是用满声的鲜血换回了公主的未来。后来，王子决定和公主举行盛大的婚礼，巫婆默默为公主缝制了最美丽的嫁衣，然后在婚礼当日消失了。多年后，王子拉着公主经过巫婆的居所，对公主说到~那里曾住着我的一个好朋友~巫婆在空中听到这句话，一滴眼泪从空中滑落，可那时她真的在笑了。
<br>&nbsp;&nbsp;有些时候不幸也许是上天注定的，但幸福却是我们自己争取的，就在我们伸出手抓住它的那一时间，巫婆的那滴眼泪，也许滴落的不是悲哀，而是没有勇气做个真正公主的遗憾。', '报上看过一则《巫婆与王子》的故事：巫婆爱上了王子，可王子却深恋着公主。有一天，公主得了重病，王子求巫婆救回他爱人脆弱的生命。那是重症，巫婆不愿看到王子伤心，于是用满声的鲜血换回了公主的未来。后来，王子决定和公主举行盛大的婚礼，巫婆默默为公主缝制了最美丽的嫁衣，然后在婚礼当日消失了。多年后，王子拉着公主经过巫婆的居所，对公主说到~那里曾住着我的一个好朋友~巫婆在空中听到这句话，一滴眼泪从空中滑落，可那时她真的在笑了。

有些时候不幸也许是上天注定的，但幸福却是我们自己争取的，就在我们伸出手抓住它的那一时间，巫婆的那滴眼泪，也许滴落的不是悲哀，而是没有勇气做个真正公主的遗憾。', NULL, '2002-07-31 08:33:00', 14, '20020821173018_bbsid_174640_board_6_bf4112d515.html', '20020821173018');
